if ( ! defined( 'ABSPATH' ) ) exit;
$plugin_url = defined( 'TPC_URL' ) ? TPC_URL : plugins_url( '', dirname( __DIR__ ) . '/senderzz-logistics.php' ) . '/';
$ajax_url   = admin_url( 'admin-ajax.php', 'relative' );
$rest_url   = rest_url();
$vapid_key  = (string) get_option( 'sz_notif_vapid_public', '' );
$logo_url   = esc_url( rtrim( $plugin_url, '/' ) . '/assets/images/senderzz-logo.png' );
$push_icon_url = esc_url( rtrim( $plugin_url, '/' ) . '/assets/images/senderzz-raio-192.png?v=244' );
$app_name  = 'Senderzz';
$reset_token = isset( $_GET['sz_reset'] ) ? sanitize_text_field( wp_unslash( $_GET['sz_reset'] ) ) : '';
$portal_url = home_url( '/meus-pedidos/' );

// Detectar se o usuário logado é afiliado puro (sem acesso de produtor)
$_sz_pwa_portal_user = null;
if ( class_exists( '\\WC_MelhorEnvio\\Portal\\Portal_Auth' ) ) {
    try { $_sz_pwa_portal_user = \WC_MelhorEnvio\Portal\Portal_Auth::get_current_user(); } catch ( Throwable $e ) {}
}
$is_pure_affiliate = false;
if ( is_object( $_sz_pwa_portal_user ) && ! empty( $_sz_pwa_portal_user->id ) ) {
    if ( function_exists( 'sz_aff_portal_user_is_affiliate_pure' ) ) {
        $is_pure_affiliate = sz_aff_portal_user_is_affiliate_pure( $_sz_pwa_portal_user );
    } elseif ( isset( $_sz_pwa_portal_user->role ) && $_sz_pwa_portal_user->role === 'affiliate' ) {
        $is_pure_affiliate = true;
    }
}

$notif_groups = [
    'Cash On Delivery' => [
        'agendamento_cod'  => '📅 Agendamento',
        'em_rota_cod'      => '🏍️ Pedido Em Rota',
        'completo_cod'     => '✅ Pedido Completo',
        'frustrado_cod'    => '❌ Pedido Frustrado',
    ],
    'Expedição' => [
        'pedido_feito'     => '🛒 Pedido Novo',
        'enviado_pad'      => '📦 Pedido Enviado',
        'entregue'         => '✅ Pedido Entregue',
    ],
];
