<div id="login-screen" class="sz-hidden"><div class="login-wrap"><div class="login-logo"><img src="<?php echo $logo_url; ?>" alt="Senderzz"></div><p id="login-msg" class="msg" style="display:none"></p><div id="login-form"><div class="field"><label>E-mail</label><input type="email" id="login-email" placeholder="seu@email.com" autocomplete="email"></div><div class="field" id="login-pass-wrap"><label>Senha</label><input type="password" id="login-pass" placeholder="••••••••" autocomplete="current-password"></div><div class="field" id="login-code-wrap" style="display:none"><label>Código recebido por e-mail</label><input type="tel" id="login-code" placeholder="000000" inputmode="numeric" autocomplete="one-time-code" maxlength="6"></div><button class="btn btn-primary" id="login-btn" onclick="App.login()">Entrar</button><button type="button" class="sz-link-btn" onclick="App.showForgot()">Esqueceu a senha?</button></div><div id="forgot-form" style="display:none"><div class="field"><label>E-mail da conta</label><input type="email" id="forgot-email" placeholder="seu@email.com" autocomplete="email"></div><button class="btn btn-primary" onclick="App.requestPasswordReset()">Enviar link de redefinição</button><button type="button" class="sz-link-btn" onclick="App.showLoginForm()">Voltar para login</button></div><div id="reset-form" style="display:none"><div class="field"><label>Nova senha</label><input type="password" id="reset-pass" placeholder="Mínimo 8 caracteres" autocomplete="new-password"></div><div class="field"><label>Confirmar nova senha</label><input type="password" id="reset-pass2" placeholder="Repita a nova senha" autocomplete="new-password"></div><button class="btn btn-primary" onclick="App.completePasswordReset()">Salvar nova senha</button><button type="button" class="sz-link-btn" onclick="App.showLoginForm()">Voltar para login</button></div></div></div>
<div class="toast" id="toast"></div><div class="modal-back" id="sz-modal"><div class="modal"><h3 id="modal-title">Solicitar saque</h3><p id="modal-text">Informe o valor desejado.</p><div class="modal-note" id="modal-note"></div><input id="modal-value" inputmode="decimal" placeholder="R$ 0,00" oninput="App.updateModalCalc()"><div class="modal-summary" id="modal-summary">Informe o valor para ver o líquido final.</div><input id="modal-code" inputmode="numeric" maxlength="6" placeholder="Código 2FA recebido por e-mail"><div class="modal-actions"><button class="btn btn-ghost" onclick="App.closeModal()">Cancelar</button><button class="btn btn-primary" id="modal-ok" onclick="App.confirmModal()">Confirmar</button></div></div></div>
<script>(function(){'use strict';
var AJAX=<?php echo wp_json_encode($ajax_url); ?>,REST=<?php echo wp_json_encode(rtrim($rest_url,'/')); ?>,VAPID=<?php echo wp_json_encode($vapid_key); ?>,SW_URL=<?php echo wp_json_encode(home_url('/app-sw.js')); ?>,RESET_TOKEN=<?php echo wp_json_encode($reset_token); ?>,NONCE='';try{AJAX=new URL(AJAX||'/wp-admin/admin-ajax.php',location.origin).toString()}catch(e){AJAX=location.origin+'/wp-admin/admin-ajax.php'}
var state={user:null,wallet:{available:0,pending:0,analysis:0,future:0,history:[]},hasSub:false,swReg:null,tempToken:'',modalMode:'withdraw'};
function toast(msg,type,dur){var t=document.getElementById('toast');t.textContent=msg;t.className='toast '+(type||'ok')+' show';clearTimeout(t._t);t._t=setTimeout(function(){t.classList.remove('show');t.textContent=''},dur||1600)}function hideToast(){var t=document.getElementById('toast');if(t){clearTimeout(t._t);t.classList.remove('show');t.textContent='';}}

function setScreen(el,mode){if(!el)return;el.classList.remove('sz-hidden','sz-visible');if(mode==='hide'){el.classList.add('sz-hidden');el.style.setProperty('display','none','important');return;}el.classList.add('sz-visible');el.style.setProperty('display',mode==='flex'?'flex':'block','important');}
function resetLoginVisual(){var b=document.getElementById('login-btn');if(b){b.disabled=false;b.innerHTML=state.tempToken?'Confirmar código':'Entrar'}var msg=document.getElementById('login-msg');if(msg&&!msg.textContent){msg.style.display='none'};}
function money(v){return 'R$ '+parseFloat(v||0).toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2})}
function ajax(data){var fd=new FormData();Object.keys(data).forEach(function(k){fd.append(k,data[k])});if(NONCE&&!fd.has('_ajax_nonce'))fd.append('_ajax_nonce',NONCE);return fetch(AJAX,{method:'POST',body:fd,credentials:'same-origin',cache:'no-store'}).then(function(r){return r.text().then(function(txt){try{return JSON.parse(txt)}catch(e){console.warn('AJAX inválido',r.status,txt.slice(0,180));throw new Error('Resposta inválida')}})})}
function loadNonce(){var fd=new FormData();fd.append('action','sz_producer_pwa_nonce');return fetch(AJAX,{method:'POST',body:fd,credentials:'same-origin',cache:'no-store'}).then(function(r){return r.json()}).then(function(d){NONCE=d&&d.nonce?d.nonce:''}).catch(function(){NONCE=''})}
function restCall(path,method,body){var opts={method:method||'GET',credentials:'same-origin',headers:{}};if(body){opts.headers['Content-Type']='application/json';opts.body=JSON.stringify(body)}return fetch(REST+path,opts).then(function(r){return r.json()})}
function b64ToUint8(b64){var pad='='.repeat((4-b64.length%4)%4);var raw=atob((b64+pad).replace(/-/g,'+').replace(/_/g,'/'));var out=new Uint8Array(raw.length);for(var i=0;i<raw.length;i++)out[i]=raw.charCodeAt(i);return out}
function checkAuth(){return ajax({action:'sz_producer_pwa',szaction:'get_current_user'}).then(function(d){if(d&&d.success&&d.data&&d.data.id){state.user=d.data;showApp()}else{state.tempToken='';showLogin()}}).catch(function(){state.tempToken='';showLogin()})}
function showApp(){if(!state.user||!state.user.id){showLogin('Sessão encerrada. Faça login novamente.');return}hideToast();setScreen(document.getElementById('loading'),'hide');setScreen(document.getElementById('login-screen'),'hide');setScreen(document.getElementById('app'),'flex');document.getElementById('profile-name').textContent=state.user.name||'Usuário Senderzz';document.getElementById('profile-email').textContent=state.user.email||'—';loadWallet();initSW()}
function showLogin(msgText){state.user=null;state.hasSub=false;setScreen(document.getElementById('loading'),'hide');setScreen(document.getElementById('app'),'hide');setScreen(document.getElementById('login-screen'),'block');var pn=document.getElementById('profile-name'),pe=document.getElementById('profile-email');if(pn)pn.textContent='—';if(pe)pe.textContent='—';var passWrap=document.getElementById('login-pass-wrap'),codeWrap=document.getElementById('login-code-wrap');if(!state.tempToken){if(passWrap)passWrap.style.display='block';if(codeWrap)codeWrap.style.display='none'}var b=document.getElementById('login-btn');if(b){b.disabled=false;b.innerHTML=state.tempToken?'Confirmar código':'Entrar'}var msg=document.getElementById('login-msg');if(msgText&&msg){msg.textContent=msgText;msg.style.display='block';msg.style.color='#E8650A';clearTimeout(msg._t);msg._t=setTimeout(function(){msg.style.display='none'},2200)}}

function setLoginMode(mode){
  var ids=['login-form','forgot-form','reset-form'];
  ids.forEach(function(id){var el=document.getElementById(id);if(el)el.style.display=(id===mode?'block':'none')});
  var msg=document.getElementById('login-msg');if(msg){msg.style.display='none';msg.textContent=''}
}
function showResetForm(){showLogin();setLoginMode('reset-form')}
function loadWallet(){ajax({action:'sz_producer_pwa',szaction:'get_cod_wallet'}).then(function(d){if(!d.success)return;state.wallet=d.data||state.wallet;renderWallet()}).catch(function(){toast('Erro ao carregar carteira','err')})}
function renderWallet(){var w=state.wallet||{};var set=function(id,val){var el=document.getElementById(id);if(el)el.textContent=money(val)};set('w-commission-pending',w.commission_pending||w.pending_commissions||w.future||0);set('w-available',w.available);set('w-pending',w.pending);set('w-analysis',w.analysis)}
function initSW(){if(!('serviceWorker'in navigator)){updateNotifUI(false);return}navigator.serviceWorker.register(SW_URL,{scope:'/app/'}).then(function(reg){state.swReg=reg;return reg.pushManager.getSubscription()}).then(function(sub){state.hasSub=!!sub;updateNotifUI(state.hasSub)}).catch(function(err){console.warn('SW error:',err);updateNotifUI(false)})}
function updateNotifUI(active){document.getElementById('notif-dot').className='notif-dot'+(active?' on':'');document.getElementById('notif-label').textContent=active?'Notificações ativas':'Notificações desativadas';var btn=document.getElementById('notif-toggle-btn');btn.textContent=active?'Desativar':'Ativar';btn.className='btn '+(active?'btn-outline':'btn-primary')}
function parseBR(v){return parseFloat(String(v||'').replace(/[^0-9,\.]/g,'').replace(',','.'))||0}
function updateModalCalc(){var v=parseBR(document.getElementById('modal-value').value),el=document.getElementById('modal-summary');if(!v){el.textContent='Informe o valor para ver o líquido final.';return}if(state.modalMode==='advance'){var fee=v*0.05,net=v-fee;el.innerHTML='Valor solicitado: <b>'+money(v)+'</b><br>Taxa de antecipação 5%: <b>'+money(fee)+'</b><br>Líquido disponibilizado: <b>'+money(net)+'</b>'}else{var fee=2.99,net=Math.max(0,v-fee);el.innerHTML='Valor solicitado: <b>'+money(v)+'</b><br>Taxa de saque: <b>'+money(fee)+'</b><br>Líquido a receber: <b>'+money(net)+'</b><br>Prazo: até 3 dias úteis.'}}
function sendFinanceCode(mode){ajax({action:'sz_producer_pwa',szaction:'finance_2fa_send',mode:mode}).then(function(d){var el=document.getElementById('modal-summary');if(el){el.innerHTML='<b>Código enviado por e-mail.</b><br>Informe o valor e confirme com o código recebido.'}setTimeout(updateModalCalc,2200)}).catch(function(){toast('Não foi possível enviar o código','err',1800)})}
window.App={nav:function(screen,btn){hideToast();document.querySelectorAll('.screen').forEach(function(s){s.classList.remove('on')});document.querySelectorAll('.nb').forEach(function(b){b.classList.remove('on')});document.getElementById('screen-'+screen).classList.add('on');btn.classList.add('on');document.getElementById('hd-title').textContent=document.getElementById('screen-'+screen).dataset.title||'Senderzz'},refresh:function(){loadWallet()},login:function(){var email=document.getElementById('login-email').value.trim(),pass=document.getElementById('login-pass').value,code=document.getElementById('login-code').value.trim(),btn=document.getElementById('login-btn'),msg=document.getElementById('login-msg'),payload;if(state.tempToken){if(!code){msg.textContent='Digite o código recebido por e-mail.';msg.style.display='block';return}payload={action:'sz_producer_pwa',szaction:'login_step2',temp_token:state.tempToken,code:code}}else{if(!email||!pass){msg.textContent='Preencha e-mail e senha.';msg.style.display='block';return}payload={action:'sz_producer_pwa',szaction:'login',email:email,password:pass}}btn.innerHTML='<span class="spin"></span>';btn.disabled=true;ajax(payload).then(function(d){if(d.success&&d.data&&d.data.needs_2fa){state.tempToken=d.data.temp_token||'';msg.textContent=d.data.message||'Código enviado.';msg.style.display='block';msg.style.color='#E8650A';clearTimeout(msg._t);msg._t=setTimeout(function(){msg.style.display='none'},2600);document.getElementById('login-pass-wrap').style.display='none';document.getElementById('login-code-wrap').style.display='block';document.getElementById('login-code').focus();btn.innerHTML='Confirmar código';btn.disabled=false;return}if(d.success){state.tempToken='';msg.style.display='none';btn.disabled=false;btn.innerHTML='Entrar';hideToast();setTimeout(checkAuth,250)}else{msg.textContent=(d.data&&d.data.message)||'Credenciais inválidas.';msg.style.display='block';msg.style.color='#dc2626';btn.innerHTML=state.tempToken?'Confirmar código':'Entrar';btn.disabled=false}}).catch(function(){msg.textContent='Erro de conexão. Recarregue o app e tente novamente.';msg.style.display='block';msg.style.color='#dc2626';btn.innerHTML=state.tempToken?'Confirmar código':'Entrar';btn.disabled=false})},logout:function(){return ajax({action:'sz_producer_pwa',szaction:'logout'}).catch(function(){}).then(function(){state.tempToken='';showLogin('Sessão encerrada. Faça login novamente.')})},showForgot:function(){setLoginMode('forgot-form');var e=document.getElementById('forgot-email'),le=document.getElementById('login-email');if(e&&le)e.value=le.value||''},showLoginForm:function(){RESET_TOKEN='';setLoginMode('login-form')},requestPasswordReset:function(){var email=(document.getElementById('forgot-email')||{}).value||'';var msg=document.getElementById('login-msg');ajax({action:'sz_producer_pwa',szaction:'request_password_reset',email:email}).then(function(d){if(msg){msg.textContent=(d.data&&d.data.message)||'Se o e-mail existir, enviaremos as instruções.';msg.style.display='block';msg.style.color=d.success?'#E8650A':'#dc2626'}if(d.success)setTimeout(function(){setLoginMode('login-form')},2200)}).catch(function(){if(msg){msg.textContent='Não foi possível enviar agora.';msg.style.display='block';msg.style.color='#dc2626'}})},completePasswordReset:function(){var p1=(document.getElementById('reset-pass')||{}).value||'',p2=(document.getElementById('reset-pass2')||{}).value||'',msg=document.getElementById('login-msg');if(p1!==p2){if(msg){msg.textContent='As senhas não conferem.';msg.style.display='block';msg.style.color='#dc2626'}return}ajax({action:'sz_producer_pwa',szaction:'complete_password_reset',token:RESET_TOKEN,new_password:p1}).then(function(d){if(msg){msg.textContent=(d.data&&d.data.message)||'Senha atualizada.';msg.style.display='block';msg.style.color=d.success?'#E8650A':'#dc2626'}if(d.success){RESET_TOKEN='';setTimeout(function(){setLoginMode('login-form')},2200)}}).catch(function(){if(msg){msg.textContent='Não foi possível alterar a senha.';msg.style.display='block';msg.style.color='#dc2626'}})},forceLogout:function(){return ajax({action:'sz_producer_pwa',szaction:'logout'}).catch(function(){}).then(function(){state.tempToken='';document.getElementById('login-pass-wrap').style.display='block';document.getElementById('login-code-wrap').style.display='none';var msg=document.getElementById('login-msg');if(msg){msg.style.display='none';msg.textContent=''};showLogin('Sessão limpa. Faça login novamente.')})},togglePush:function(){if(!('Notification'in window)){toast('Navegador sem suporte','err');return}if(state.hasSub){state.swReg.pushManager.getSubscription().then(function(sub){if(!sub)return;sub.unsubscribe().then(function(){restCall('/sz-notif/v1/unsubscribe','POST',{endpoint:sub.endpoint});state.hasSub=false;updateNotifUI(false);toast('Notificações desativadas')})})}else{Notification.requestPermission().then(function(perm){if(perm!=='granted'){toast('Permissão negada no celular','err',3500);return}if(!VAPID){toast('Push não configurado','err');return}state.swReg.pushManager.subscribe({userVisibleOnly:true,applicationServerKey:b64ToUint8(VAPID)}).then(function(sub){var j=sub.toJSON();return restCall('/sz-notif/v1/subscribe','POST',{endpoint:j.endpoint,p256dh:j.keys.p256dh,auth:j.keys.auth})}).then(function(){state.hasSub=true;updateNotifUI(true);toast('Notificações ativadas! 🔔')}).catch(function(e){toast('Erro: '+e.message,'err',3500)})})}},savePref:function(chk){var prefs={};prefs[chk.dataset.event]={enabled:chk.checked?1:0,include_affiliates:(document.querySelector('[data-event=\"replicar_afiliados\"]')&&document.querySelector('[data-event=\"replicar_afiliados\"]').checked)?1:0};restCall('/sz-notif/v1/prefs','POST',{prefs:prefs}).then(function(d){toast(d.msg||(chk.checked?'Ativado':'Desativado'),'ok',1200)}).catch(function(){toast('Erro ao salvar','err')})},testPush:function(){if(!state.hasSub){toast('Ative as notificações primeiro','err');return}state.swReg.showNotification('🔔 Teste Senderzz',{body:'Notificações funcionando!',icon:<?php echo wp_json_encode($push_icon_url); ?>,badge:<?php echo wp_json_encode($push_icon_url); ?>,tag:'sz-test-'+Date.now()}).then(function(){toast('Notificação enviada!')})},openWithdraw:function(){state.modalMode='withdraw';document.getElementById('modal-title').textContent='Solicitar saque';document.getElementById('modal-text').textContent='Informe o valor para solicitar saque COD. O saldo sai de disponível e fica em análise.';document.getElementById('modal-note').textContent='Custo fixo de saque: R$ 2,99. Prazo estimado: até 3 dias úteis. Será exigido código de autenticação por e-mail.';document.getElementById('modal-value').value='';document.getElementById('modal-code').value='';updateModalCalc();document.getElementById('modal-ok').textContent='Solicitar saque';document.getElementById('sz-modal').classList.add('on');sendFinanceCode('withdraw')},openAdvance:function(){state.modalMode='advance';document.getElementById('modal-title').textContent='Antecipar valores';document.getElementById('modal-text').textContent='Informe o valor que deseja antecipar do saldo pendente para o saldo disponível.';document.getElementById('modal-note').textContent='Taxa de antecipação: 5%. Após aprovação, o valor líquido passa de saldo pendente para saldo disponível. Será exigido código de autenticação por e-mail.';document.getElementById('modal-value').value='';document.getElementById('modal-code').value='';updateModalCalc();document.getElementById('modal-ok').textContent='Antecipar';document.getElementById('sz-modal').classList.add('on');sendFinanceCode('advance')},closeModal:function(){document.getElementById('sz-modal').classList.remove('on')},updateModalCalc:updateModalCalc,confirmModal:function(){var v=document.getElementById('modal-value').value.replace(/[^0-9,\.]/g,'').replace(',','.'),code=document.getElementById('modal-code').value.trim();if(!code||code.length<6){toast('Digite o código 2FA recebido por e-mail','err');return}ajax({action:'sz_producer_pwa',szaction:state.modalMode==='advance'?'request_advance':'request_withdraw',valor:v,auth_code:code}).then(function(d){toast((d.data&&d.data.message)||d.message||(d.success?'Solicitação enviada':'Não foi possível'),d.success?'ok':'err',3000);if(d.success){App.closeModal();loadWallet()}}).catch(function(){toast('Erro ao solicitar','err')})}};
loadNonce().then(function(){ if(RESET_TOKEN){ showResetForm(); } else { checkAuth(); } });document.addEventListener('keydown',function(e){if(e.key==='Enter'&&document.getElementById('login-screen').style.display!=='none')App.login()});
})();</script></body></html>
